import openpyxl

def solve():
    # Load the source workbook with data_only=True to read calculated values instead of formulas
    wb_source = openpyxl.load_workbook('source.xlsx', data_only=True)
    ws_source = wb_source['sheet1']

    # Get the value of the second row in column G (row 2, column 7)
    g2_value = ws_source.cell(row=2, column=7).value

    if g2_value is not None:
        try:
            g2_value = float(g2_value)
        except (ValueError, TypeError):
            g2_value = None

    if g2_value is not None:
        filtered_data = {}

        # Iterate through all rows in the source sheet
        for row in range(1, ws_source.max_row + 1):
            d_val = ws_source.cell(row=row, column=4).value
            f_val = ws_source.cell(row=row, column=6).value
            g_val = ws_source.cell(row=row, column=7).value

            if d_val is not None and f_val is not None and g_val is not None:
                try:
                    d_float = float(d_val)
                    f_float = float(f_val)
                    g_float = float(g_val)

                    # Apply the filtering conditions
                    if d_float >= 8 and d_float < 8.0010 and f_float == 18 and g_float > g2_value:
                        filtered_data[row] = g_val
                except (ValueError, TypeError):
                    # Skip rows that cannot be converted to float (e.g., headers)
                    continue

        # Load the target workbook
        wb_target = openpyxl.load_workbook('target.xlsx')
        ws_target = wb_target['sheet1']

        # Paste the filtered values into the corresponding cells in the target sheet
        for row, val in filtered_data.items():
            ws_target.cell(row=row, column=7).value = val

        # Save the target workbook
        wb_target.save('target.xlsx')

if __name__ == '__main__':
    solve()
